import React, { useEffect, useState, Component } from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Layout } from './components/layout/Layout';
import { UserProvider, useUser } from './context/UserContext';
import HomePage from './pages/HomePage';
import FoodDetailPage from './pages/FoodDetailPage';
import TopicsPage from './pages/TopicsPage';
import AboutPage from './pages/AboutPage';
import SettingsPage from './pages/SettingsPage';
import OnboardingPage from './pages/OnboardingPage';
import PremiumPage from './pages/PremiumPage';
import AuthCallback from './pages/AuthCallback';
import { TermsPage, PrivacyPage, SupportPage } from './pages/LegalPages';
import { AllQuestionsPage } from './components/common/FrequentQuestions';
import { checkAndInvalidateCache } from './utils/cache';
import './App.css';

// Check if cache needs to be invalidated due to data structure changes
// This runs once when the app loads
checkAndInvalidateCache();

// Error Boundary to catch rendering crashes
class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // Log detailed error information
    console.error('[ErrorBoundary] Caught error:', error);
    console.error('[ErrorBoundary] Error message:', error?.message || 'No message');
    console.error('[ErrorBoundary] Error name:', error?.name || 'No name');
    console.error('[ErrorBoundary] Error stack:', error?.stack || 'No stack');
    console.error('[ErrorBoundary] Component stack:', errorInfo?.componentStack || 'No component stack');
    this.setState({ errorInfo });
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl p-6 max-w-md shadow-lg text-center">
            <h2 className="text-xl font-semibold text-stone-800 mb-3">Something went wrong</h2>
            <p className="text-stone-600 text-sm mb-4">
              The app encountered an error. Please try refreshing the page.
            </p>
            <button 
              onClick={() => {
                // Clear potentially corrupted cache/state
                try {
                  localStorage.removeItem('whattoeat_cache_foods_all');
                  localStorage.removeItem('whattoeat_cache_categories');
                } catch(e) {}
                window.location.reload();
              }}
              className="bg-emerald-600 text-white px-6 py-2 rounded-lg font-medium"
            >
              Refresh App
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

// Protected Route wrapper - requires disclaimer acceptance per session AND completed onboarding
function ProtectedRoute({ children }) {
  const { hasCompletedOnboarding, user } = useUser();
  const [hasChecked, setHasChecked] = useState(false);
  const [isAllowed, setIsAllowed] = useState(false);
  
  useEffect(() => {
    // CRITICAL: Check if disclaimer was accepted THIS SESSION (required on every app launch)
    const disclaimerAcceptedThisSession = sessionStorage.getItem('disclaimer_accepted_session') === 'true';
    
    // If disclaimer not accepted this session, always redirect to onboarding
    if (!disclaimerAcceptedThisSession) {
      setIsAllowed(false);
      setHasChecked(true);
      return;
    }
    
    // Check other conditions for allowing access
    const navigatingToPremium = sessionStorage.getItem('navigateToPremium') === 'true';
    const continuedFromPremium = sessionStorage.getItem('continuedFromPremium') === 'true';
    
    // Also check localStorage directly for onboardingCompleted (handles race conditions)
    let localStorageOnboarded = false;
    try {
      const userStr = localStorage.getItem('whattoeat_user');
      if (userStr) {
        const userData = JSON.parse(userStr);
        localStorageOnboarded = userData.onboardingCompleted === true;
      }
    } catch (e) {
      // Ignore parse errors
    }
    
    // Determine if user should be allowed (disclaimer already checked above)
    const shouldAllow = hasCompletedOnboarding() || navigatingToPremium || continuedFromPremium || localStorageOnboarded;
    
    // Clear session flags after checking
    if (continuedFromPremium && shouldAllow) {
      sessionStorage.removeItem('continuedFromPremium');
    }
    
    setIsAllowed(shouldAllow);
    setHasChecked(true);
  }, [hasCompletedOnboarding, user]);
  
  // Show loading while checking
  if (!hasChecked) {
    return (
      <div className="min-h-screen bg-stone-50 flex items-center justify-center">
        <div className="w-8 h-8 border-3 border-emerald-600 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }
  
  if (!isAllowed) {
    return <Navigate to="/onboarding" replace />;
  }
  
  return children;
}

// Layout wrapper for main app routes
function MainLayout({ children }) {
  return <Layout>{children}</Layout>;
}

function AppContent() {
  const { loading, hasCompletedOnboarding, isPremium, user } = useUser();
  const location = useLocation();

  // CRITICAL: Check URL hash for session_id synchronously during render
  // This must happen BEFORE Routes to prevent race conditions with ProtectedRoute
  if (location.hash?.includes('session_id=')) {
    return <AuthCallback />;
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-stone-50 flex items-center justify-center">
        <div className="w-8 h-8 border-3 border-emerald-600 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  // Check if we're trying to navigate to premium after signup
  const isNavigatingToPremium = location.pathname === '/premium' || 
                                 sessionStorage.getItem('navigateToPremium') === 'true';

  return (
    <Routes>
      {/* Onboarding - must show disclaimer every session, then redirect if already completed */}
      <Route
        path="/onboarding"
        element={
          // Always show OnboardingPage for disclaimer acceptance per session
          // OnboardingPage will handle redirect after disclaimer is accepted
          <OnboardingPage />
        }
      />

      {/* Main app routes - accessible to all logged-in users (free and premium) */}
      <Route
        path="/"
        element={
          <ProtectedRoute>
            <MainLayout>
              <HomePage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/home"
        element={
          <ProtectedRoute>
            <MainLayout>
              <HomePage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/food/:id"
        element={
          <ProtectedRoute>
            <MainLayout>
              <FoodDetailPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/topics"
        element={
          <ProtectedRoute>
            <MainLayout>
              <TopicsPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/about"
        element={
          <ProtectedRoute>
            <MainLayout>
              <AboutPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/settings"
        element={
          <ProtectedRoute>
            <MainLayout>
              <SettingsPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      {/* Premium page - accessible after signup (no ProtectedRoute - uses its own auth check) */}
      <Route
        path="/premium"
        element={<PremiumPage />}
      />
      {/* Questions page - all pregnancy food questions */}
      <Route
        path="/questions"
        element={
          <ProtectedRoute>
            <MainLayout>
              <AllQuestionsPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      {/* FAQ page - same as questions, accessible from bottom nav */}
      <Route
        path="/faq"
        element={
          <ProtectedRoute>
            <MainLayout>
              <AllQuestionsPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/terms"
        element={
          <ProtectedRoute>
            <MainLayout>
              <TermsPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/privacy"
        element={
          <ProtectedRoute>
            <MainLayout>
              <PrivacyPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />
      <Route
        path="/support"
        element={
          <ProtectedRoute>
            <MainLayout>
              <SupportPage />
            </MainLayout>
          </ProtectedRoute>
        }
      />

      {/* Fallback - show home page for any unmatched routes */}
      <Route 
        path="*" 
        element={
          <ProtectedRoute>
            <MainLayout>
              <HomePage />
            </MainLayout>
          </ProtectedRoute>
        } 
      />
    </Routes>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <UserProvider>
        <HashRouter>
          <AppContent />
        </HashRouter>
      </UserProvider>
    </ErrorBoundary>
  );
}

export default App;
