// Apple In-App Purchase Service
// Uses cordova-plugin-purchase for StoreKit integration

const PRODUCT_ID = 'whattoeat_premium_yearly';

class InAppPurchaseService {
  constructor() {
    this.store = null;
    this.product = null;
    this.isReady = false;
    this.onPurchaseUpdate = null;
  }

  async initialize() {
    // Check if running in Capacitor/Cordova environment
    if (typeof window.CdvPurchase === 'undefined') {
      console.log('In-App Purchase not available (not on device)');
      return false;
    }

    try {
      this.store = window.CdvPurchase.store;
      
      // Register the product - Non-Renewing Subscription for 12 months
      this.store.register([{
        id: PRODUCT_ID,
        type: window.CdvPurchase.ProductType.NON_RENEWING_SUBSCRIPTION,
        platform: window.CdvPurchase.Platform.APPLE_APPSTORE,
      }]);

      // Set up event handlers
      this.store.when()
        .productUpdated((product) => {
          console.log('Product updated:', product);
          this.product = product;
          if (this.onPurchaseUpdate) {
            this.onPurchaseUpdate({ type: 'productUpdated', product });
          }
        })
        .approved((transaction) => {
          console.log('Purchase approved:', transaction);
          transaction.verify();
        })
        .verified((receipt) => {
          console.log('Purchase verified:', receipt);
          receipt.finish();
          if (this.onPurchaseUpdate) {
            this.onPurchaseUpdate({ type: 'verified', receipt });
          }
        })
        .finished((transaction) => {
          console.log('Purchase finished:', transaction);
          if (this.onPurchaseUpdate) {
            this.onPurchaseUpdate({ type: 'finished', transaction });
          }
        })
        .error((error) => {
          console.error('Store error:', error);
          if (this.onPurchaseUpdate) {
            this.onPurchaseUpdate({ type: 'error', error });
          }
        });

      // Initialize the store
      await this.store.initialize([window.CdvPurchase.Platform.APPLE_APPSTORE]);
      
      // Refresh products
      await this.store.refresh();
      
      this.isReady = true;
      return true;
    } catch (error) {
      console.error('Failed to initialize IAP:', error);
      return false;
    }
  }

  getProduct() {
    if (!this.store) return null;
    return this.store.get(PRODUCT_ID);
  }

  getPrice() {
    const product = this.getProduct();
    if (product && product.pricing) {
      return product.pricing.price;
    }
    return '$1.99'; // Fallback for development
  }

  getPriceLabel() {
    return 'One-time purchase • 12 months access';
  }

  async purchase() {
    if (!this.store) {
      console.error('Store not initialized');
      return { success: false, error: 'Store not available' };
    }

    const product = this.getProduct();
    if (!product) {
      console.error('Product not found');
      return { success: false, error: 'Product not available' };
    }

    try {
      const offer = product.getOffer();
      if (offer) {
        await this.store.order(offer);
        return { success: true };
      } else {
        return { success: false, error: 'No offer available' };
      }
    } catch (error) {
      console.error('Purchase error:', error);
      return { success: false, error: error.message };
    }
  }

  async restorePurchases() {
    if (!this.store) {
      console.error('Store not initialized');
      return { success: false, error: 'Store not available' };
    }

    try {
      await this.store.restorePurchases();
      return { success: true };
    } catch (error) {
      console.error('Restore error:', error);
      return { success: false, error: error.message };
    }
  }

  isPremiumActive() {
    const product = this.getProduct();
    if (product && product.owned) {
      return true;
    }
    return false;
  }

  setUpdateCallback(callback) {
    this.onPurchaseUpdate = callback;
  }
}

// Singleton instance
const iapService = new InAppPurchaseService();

export default iapService;
export { PRODUCT_ID };
