import axios from 'axios';
import { Capacitor } from '@capacitor/core';
import { 
  getFromCache, 
  saveToCache, 
  CACHE_KEYS, 
  CACHE_DURATIONS 
} from '../utils/cache';

// Production API URL for native builds (iOS/Android)
const NATIVE_API_URL = 'https://health-ed-guide.emergent.host';

// Detect if running in a native Capacitor environment
const isRunningInCapacitor = () => {
  // Check multiple indicators for native platform
  if (typeof window === 'undefined') return false;
  
  // Check if URL scheme is capacitor://
  if (window.location.protocol === 'capacitor:') return true;
  
  // Check Capacitor object methods
  try {
    if (Capacitor.isNativePlatform && Capacitor.isNativePlatform()) return true;
    if (Capacitor.getPlatform && Capacitor.getPlatform() !== 'web') return true;
  } catch (e) {
    // Capacitor methods might not be available
  }
  
  // Check for iOS/Android user agent patterns that indicate WebView
  const ua = navigator.userAgent || '';
  if (ua.includes('Capacitor') || ua.includes('ionic')) return true;
  
  return false;
};

// Get the API base URL
const getApiBaseUrl = () => {
  const envUrl = process.env.REACT_APP_BACKEND_URL;
  
  // 1. Always prefer environment variable if set and valid
  if (envUrl && envUrl.startsWith('http')) {
    console.log('[API] Using env URL:', envUrl);
    return envUrl;
  }
  
  // 2. For native platforms (iOS/Android), use production URL
  if (isRunningInCapacitor()) {
    console.log('[API] Capacitor detected, using production URL:', NATIVE_API_URL);
    return NATIVE_API_URL;
  }
  
  // 3. Web fallback - use current origin (for development)
  console.warn('[API] No env URL, using origin');
  return window.location.origin;
};

const API_BASE = getApiBaseUrl();

// Log API base on module load
console.log('[API] Module loaded, API_BASE:', API_BASE);

const api = axios.create({
  baseURL: `${API_BASE}/api`,
  headers: {
    'Content-Type': 'application/json',
  },
  // Add timeout to prevent hanging requests
  timeout: 30000,
});

// Add auth token to requests if available
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('whattoeat_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  // Log the full URL being requested for debugging
  console.log('[API] Request:', config.method?.toUpperCase(), config.baseURL + config.url);
  return config;
});

// Add response interceptor to handle JSON string responses (iOS WebView issue)
api.interceptors.response.use((response) => {
  // Log for debugging
  console.log('[API] Response type:', typeof response.data, 'value preview:', 
    typeof response.data === 'string' ? response.data.substring(0, 100) : 'not-string');
  
  // If response.data is a string, try to parse it as JSON
  if (typeof response.data === 'string') {
    // Handle empty or whitespace-only strings
    const trimmed = response.data.trim();
    if (!trimmed || trimmed === '') {
      console.warn('[API] Empty string response, returning empty array');
      response.data = [];
      return response;
    }
    
    try {
      let parsed = JSON.parse(trimmed);
      // Handle double-stringified JSON (iOS WebView can do this)
      if (typeof parsed === 'string') {
        try {
          parsed = JSON.parse(parsed);
        } catch (e2) {
          // Keep the first parse result
        }
      }
      response.data = parsed;
    } catch (e) {
      // If parsing fails, check if it looks like JSON or HTML
      console.warn('[API] Failed to parse response as JSON:', e.message || e);
      
      // If the response is HTML (starts with <!doctype or <html), this is a routing error
      if (trimmed.toLowerCase().startsWith('<!doctype') || trimmed.toLowerCase().startsWith('<html')) {
        console.error('[API] Received HTML instead of JSON - API URL may be misconfigured');
        console.error('[API] Current API_BASE:', API_BASE);
        response.data = [];
        return response;
      }
      
      // Return empty array if it looks like it should be an array
      if (trimmed.startsWith('[') || trimmed.startsWith('{')) {
        console.warn('[API] Response looks like JSON but failed to parse, returning empty');
        response.data = [];
      }
    }
  }
  return response;
}, (error) => {
  console.error('[API] Request error:', error.message || error);
  return Promise.reject(error);
});

// Helper to ensure data is parsed (for cached data)
function ensureParsed(data) {
  if (typeof data === 'string') {
    try {
      return JSON.parse(data);
    } catch (e) {
      return data;
    }
  }
  return data;
}

// Helper function to fetch with cache
async function fetchWithCache(key, fetcher, duration = CACHE_DURATIONS.LONG) {
  // Try to get from cache first
  const cached = getFromCache(key);
  if (cached) {
    // Ensure cached data is parsed
    const parsedData = ensureParsed(cached);
    return { data: parsedData, fromCache: true };
  }
  
  // Fetch from server
  const response = await fetcher();
  
  // Ensure response data is parsed before caching
  const parsedData = ensureParsed(response.data);
  
  // Save to cache
  saveToCache(key, parsedData, duration);
  
  // Return with parsed data
  return { ...response, data: parsedData };
}

// Auth API
export const authApi = {
  register: (userData) => api.post('/auth/register', userData),
  login: (email, password) => api.post('/auth/login', { email, password }),
  googleAuth: (sessionId) => api.post('/auth/google/session', { session_id: sessionId }),
  appleAuth: (appleData) => api.post('/auth/apple', {
    identity_token: appleData.identityToken,
    authorization_code: appleData.authorizationCode,
    apple_user_id: appleData.appleUserId,
    email: appleData.email,
    full_name: appleData.fullName,
  }),
  logout: () => api.post('/auth/logout'),
  getProfile: () => api.get('/auth/me'),
  updateProfile: (data) => api.put('/auth/profile', data),
  deleteAccount: () => api.delete('/auth/account'),
};

// Foods API with caching
export const foodsApi = {
  getAll: async () => {
    return fetchWithCache(
      CACHE_KEYS.FOODS_ALL, 
      () => api.get('/foods'),
      CACHE_DURATIONS.LONG
    );
  },
  getById: async (id) => {
    return fetchWithCache(
      CACHE_KEYS.FOOD_DETAIL(id),
      () => api.get(`/foods/${id}`),
      CACHE_DURATIONS.LONG
    );
  },
  search: (query) => api.get(`/foods/search?q=${encodeURIComponent(query)}`),
  getByCategory: (category) => api.get(`/foods/category/${encodeURIComponent(category)}`),
  getBySafety: (level) => api.get(`/foods/safety/${level}`),
  getPersonalized: (healthConditions, trimester) => api.post('/foods/personalized', {
    health_conditions: healthConditions || [],
    trimester: trimester || null
  }),
  getForCondition: (condition) => api.get(`/foods/recommended/${condition}`),
};

// Categories API with caching
export const categoriesApi = {
  getAll: async () => {
    return fetchWithCache(
      CACHE_KEYS.CATEGORIES,
      () => api.get('/categories'),
      CACHE_DURATIONS.LONG
    );
  },
};

