import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Home, Search, BookOpen, Info, Settings, ChevronLeft, User, HelpCircle, LogOut } from 'lucide-react';
import { useUser } from '../../context/UserContext';

export function Header() {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, isAuthenticated, isPremium, hasCompletedOnboarding, logout } = useUser();
  
  // Show back button on all pages except:
  // 1. The disclaimer (first step of onboarding)
  // 2. The Home page (root of the app - no back navigation)
  const isDisclaimerStep = location.pathname === '/onboarding' && !sessionStorage.getItem('passed_disclaimer');
  const isHomePage = location.pathname === '/' || location.pathname === '/home';
  const showBackButton = !isDisclaimerStep && !isHomePage;
  
  // Navigate based on user status when clicking logo
  const handleLogoClick = (e) => {
    e.preventDefault();
    if (isPremium()) {
      navigate('/');
    } else if (hasCompletedOnboarding()) {
      navigate('/premium');
    } else {
      navigate('/onboarding');
    }
  };

  const handleBack = () => {
    // If on home page - don't navigate anywhere (this is the app's main entry point)
    // On iOS, the user would use the system gesture to close the app
    if (location.pathname === '/' || location.pathname === '/home') {
      // Do nothing - Home is the root of the app
      return;
    } else if (location.pathname === '/premium') {
      // On Premium page, go back to home (free users can access home now)
      navigate('/');
    } else {
      // For other pages, try going back in history
      // If no history, go to home
      if (window.history.length <= 2) {
        navigate('/');
      } else {
        navigate(-1);
      }
    }
  };

  // Handle logout - clears session and returns to disclaimer
  const handleLogout = () => {
    if (logout) {
      logout();
    }
    // Clear all storage
    localStorage.clear();
    sessionStorage.clear();
    // Navigate to onboarding/disclaimer
    navigate('/onboarding');
    // Force reload to reset app state
    window.location.reload();
  };
  
  return (
    <header className="bg-white border-b border-stone-200 sticky top-0 z-40">
      <div className="max-w-4xl mx-auto px-4 py-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            {showBackButton && (
              <button
                onClick={handleBack}
                className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-stone-100 transition-colors text-stone-600"
                data-testid="back-button"
              >
                <ChevronLeft size={24} />
              </button>
            )}
            <button onClick={handleLogoClick} className="flex items-center gap-2" data-testid="logo-btn">
              <div className="w-8 h-8 bg-emerald-600 rounded-lg flex items-center justify-center">
                <span className="text-white font-bold text-sm">W</span>
              </div>
              <h1 className="text-lg font-semibold text-stone-800">WhatToEat</h1>
            </button>
          </div>
          
          {/* Header Right Actions */}
          <div className="flex items-center gap-2">
            {/* Logout Button - only show on Home page */}
            {isHomePage && isAuthenticated?.() && (
              <button
                onClick={handleLogout}
                className="w-9 h-9 flex items-center justify-center rounded-full bg-stone-100 hover:bg-red-100 hover:text-red-600 transition-colors"
                data-testid="logout-button"
                title="Log Out"
              >
                <LogOut size={18} className="text-stone-600" />
              </button>
            )}
            
            {/* Account/Profile Button */}
            <button
              onClick={() => navigate(isAuthenticated() ? '/settings' : '/onboarding')}
              className="w-9 h-9 flex items-center justify-center rounded-full bg-stone-100 hover:bg-stone-200 transition-colors"
              data-testid="profile-button"
            >
              <User size={18} className="text-stone-600" />
            </button>
          </div>
        </div>
      </div>
    </header>
  );
}

export function Footer() {
  const location = useLocation();
  const navigate = useNavigate();
  const { isPremium, hasCompletedOnboarding } = useUser();
  
  // Home path: All logged-in users go to / (HomePage handles premium upsell)
  const homePath = hasCompletedOnboarding() ? '/' : '/onboarding';
  
  const navItems = [
    { path: homePath, icon: Home, label: 'Home' },
    { path: '/faq', icon: HelpCircle, label: 'FAQ' },
    { path: '/topics', icon: BookOpen, label: 'Topics' },
    { path: '/about', icon: Info, label: 'About' },
    { path: '/settings', icon: Settings, label: 'Settings' },
  ];

  return (
    <footer className="fixed bottom-0 left-0 right-0 bg-white border-t border-stone-200 z-40">
      <nav className="max-w-4xl mx-auto px-4">
        <ul className="flex justify-around py-2">
          {navItems.map(({ path, icon: Icon, label }) => {
            const isActive = location.pathname === path || 
              (label === 'Home' && (location.pathname === '/' || location.pathname === '/onboarding')) ||
              (label === 'FAQ' && (location.pathname === '/faq' || location.pathname === '/questions'));
            return (
              <li key={label}>
                <Link
                  to={path}
                  className={`flex flex-col items-center gap-1 px-3 py-1 rounded-lg transition-colors ${
                    isActive 
                      ? 'text-emerald-600' 
                      : 'text-stone-500 hover:text-stone-700'
                  }`}
                  data-testid={`nav-${label.toLowerCase()}`}
                >
                  <Icon size={20} />
                  <span className="text-xs">{label}</span>
                </Link>
              </li>
            );
          })}
        </ul>
      </nav>
    </footer>
  );
}

export function Layout({ children }) {
  return (
    <div className="min-h-screen bg-stone-50">
      <Header />
      <main className="pb-20">
        {children}
      </main>
      <Footer />
    </div>
  );
}

export function DisclaimerModal({ onAccept }) {
  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl max-w-md w-full p-6 shadow-xl">
        <h2 className="text-xl font-semibold text-stone-800 mb-4">
          Important Notice
        </h2>
        <div className="space-y-3 text-sm text-stone-600 mb-6">
          <p>
            This app provides <strong>general educational information</strong> about 
            nutrition during pregnancy compiled from public health sources.
          </p>
          <p>
            This is <strong>not medical advice</strong>. It does not replace consultation 
            with qualified healthcare professionals.
          </p>
          <p>
            Individual circumstances vary. Please consult your healthcare provider for 
            personalized guidance.
          </p>
        </div>
        <button
          onClick={onAccept}
          className="w-full bg-emerald-600 text-white py-3 rounded-lg font-medium hover:bg-emerald-700 transition-colors"
          data-testid="disclaimer-accept-btn"
        >
          I Understand
        </button>
      </div>
    </div>
  );
}
