import React, { useState, useEffect, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { foodsApi, categoriesApi } from '../api';
import { FoodGrid } from '../components/food/FoodCard';
import { SearchBar, CategoryFilter, SafetyFilter, Disclaimer } from '../components/common/Filters';
import DailyTip from '../components/common/DailyTip';
import { useUser } from '../context/UserContext';
import { Sparkles, AlertTriangle, Info, Lock, RefreshCw } from 'lucide-react';
import { clearAllCache } from '../utils/cache';

// Premium foods are now determined by the 'premium' field from the API
// No hardcoded list needed - the backend defines what's premium

export default function HomePage() {
  const navigate = useNavigate();
  const userContext = useUser();
  // Safely destructure with fallbacks
  const user = userContext?.user || null;
  const isPremium = userContext?.isPremium || (() => false);
  
  // Check if user has any personalization data
  const hasPersonalizationData = user && ((user?.dietaryRestrictions?.length || 0) > 0 || user?.trimester);
  
  const [foods, setFoods] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [selectedSafety, setSelectedSafety] = useState(null);
  const [recommendations, setRecommendations] = useState(null);
  // Default to personalized view only if user has personalization data
  const [showPersonalized, setShowPersonalized] = useState(false);
  const [error, setError] = useState(null);

  // Update showPersonalized when user data changes
  useEffect(() => {
    if (hasPersonalizationData) {
      setShowPersonalized(true);
    }
  }, [hasPersonalizationData]);

  // Debug logging for iOS simulator issues
  useEffect(() => {
    console.log('[HomePage] Mounted');
    console.log('[HomePage] User context:', userContext ? 'available' : 'null');
    console.log('[HomePage] User:', user ? JSON.stringify({ trimester: user.trimester, dietaryRestrictions: user.dietaryRestrictions }) : 'null');
    console.log('[HomePage] hasPersonalizationData:', hasPersonalizationData);
    return () => console.log('[HomePage] Unmounting');
  }, []);

  useEffect(() => {
    let isMounted = true;
    
    async function fetchData() {
      if (!isMounted) return;
      setError(null);
      console.log('[HomePage] fetchData starting...');
      
      try {
        // Get user data safely - these may be null during initial render
        const trimester = user?.trimester || null;
        const healthConditions = user?.dietaryRestrictions || [];
        
        console.log('[HomePage] User trimester:', trimester);
        console.log('[HomePage] User conditions:', healthConditions);
        console.log('[HomePage] showPersonalized:', showPersonalized);
        
        // Only use personalized view if user has actual personalization data
        const shouldPersonalize = showPersonalized && (healthConditions.length > 0 || trimester);
        console.log('[HomePage] shouldPersonalize:', shouldPersonalize);
        
        // Fetch personalized foods if user has conditions, otherwise fetch all
        if (shouldPersonalize) {
          console.log('[HomePage] Fetching personalized foods...');
          const [personalizedRes, categoriesRes] = await Promise.all([
            foodsApi.getPersonalized(healthConditions, trimester),
            categoriesApi.getAll(),
          ]);
          if (!isMounted) return;
          console.log('[HomePage] Personalized response:', personalizedRes?.data ? 'received' : 'empty');
          setFoods(personalizedRes?.data?.foods || []);
          setRecommendations(personalizedRes?.data?.recommendations || null);
          // Ensure categories is always an array
          const cats = categoriesRes?.data;
          console.log('[HomePage] Categories:', Array.isArray(cats) ? cats.length : 'not array');
          setCategories(Array.isArray(cats) ? cats : []);
        } else {
          console.log('[HomePage] Fetching all foods...');
          const [foodsRes, categoriesRes] = await Promise.all([
            foodsApi.getAll(),
            categoriesApi.getAll(),
          ]);
          if (!isMounted) return;
          
          // Handle different response formats - iOS WebView may return strings
          let foodsData = foodsRes?.data;
          console.log('[HomePage] Foods response type:', typeof foodsData, Array.isArray(foodsData));
          console.log('[HomePage] Foods response preview:', typeof foodsData === 'string' ? foodsData.substring(0, 200) : 'not-string');
          
          // Parse if it's a string (iOS WebView issue)
          if (typeof foodsData === 'string') {
            try {
              foodsData = JSON.parse(foodsData);
              console.log('[HomePage] Parsed foods string to:', typeof foodsData, Array.isArray(foodsData));
            } catch (parseErr) {
              console.error('[HomePage] Failed to parse foods string:', parseErr);
              foodsData = [];
            }
          }
          
          // If data is not an array, it might be wrapped
          if (!Array.isArray(foodsData) && foodsData?.foods) {
            foodsData = foodsData.foods;
          }
          
          console.log('[HomePage] Foods count:', Array.isArray(foodsData) ? foodsData.length : 0);
          setFoods(Array.isArray(foodsData) ? foodsData : []);
          setRecommendations(null);
          
          // Handle categories - also parse if string
          let cats = categoriesRes?.data;
          console.log('[HomePage] Categories response type:', typeof cats, Array.isArray(cats));
          
          if (typeof cats === 'string') {
            try {
              cats = JSON.parse(cats);
              console.log('[HomePage] Parsed categories string to:', typeof cats, Array.isArray(cats));
            } catch (parseErr) {
              console.error('[HomePage] Failed to parse categories string:', parseErr);
              cats = [];
            }
          }
          
          setCategories(Array.isArray(cats) ? cats : []);
        }
      } catch (error) {
        console.error('[HomePage] Error fetching data:', error?.message || error);
        if (!isMounted) return;
        setError('Unable to load food data. Please check your connection.');
        // Fallback to non-personalized
        try {
          console.log('[HomePage] Attempting fallback fetch...');
          const [foodsRes, categoriesRes] = await Promise.all([
            foodsApi.getAll(),
            categoriesApi.getAll(),
          ]);
          if (!isMounted) return;
          
          let foodsData = foodsRes?.data;
          if (!Array.isArray(foodsData) && foodsData?.foods) {
            foodsData = foodsData.foods;
          }
          
          setFoods(Array.isArray(foodsData) ? foodsData : []);
          const cats = categoriesRes?.data;
          setCategories(Array.isArray(cats) ? cats : []);
          setError(null); // Clear error if fallback succeeds
        } catch (e) {
          console.error('[HomePage] Fallback fetch failed:', e?.message || e);
          if (!isMounted) return;
          // Set safe empty defaults
          setFoods([]);
          setCategories([]);
          setRecommendations(null);
        }
      } finally {
        if (isMounted) {
          setLoading(false);
          console.log('[HomePage] fetchData complete');
        }
      }
    }
    
    fetchData();
    
    return () => {
      isMounted = false;
    };
  }, [showPersonalized, user?.trimester, user?.dietaryRestrictions]);

  const filteredFoods = useMemo(() => {
    // Ensure foods is always an array
    let result = Array.isArray(foods) ? foods : [];

    // Search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      result = result.filter(
        (food) =>
          food?.name?.toLowerCase()?.includes(query) ||
          food?.category?.toLowerCase()?.includes(query) ||
          food?.description?.toLowerCase()?.includes(query)
      );
    }

    // Category filter
    if (selectedCategory) {
      result = result.filter((food) => food?.category === selectedCategory);
    }

    // Safety filter
    if (selectedSafety) {
      result = result.filter((food) => food?.safety_level === selectedSafety);
    }

    return result;
  }, [foods, searchQuery, selectedCategory, selectedSafety]);

  // Show all filtered foods (not sliced) - FoodGrid will handle locked state
  const displayedFoods = useMemo(() => {
    // Ensure filteredFoods is always an array
    return Array.isArray(filteredFoods) ? filteredFoods : [];
  }, [filteredFoods]);

  // Count premium (locked) foods for free users using the API's premium field
  const premiumFoodsCount = useMemo(() => {
    if (isPremium?.()) return 0;
    return displayedFoods.filter(f => f?.premium === true).length;
  }, [displayedFoods, isPremium]);

  const freeFoodsCount = useMemo(() => {
    return displayedFoods.filter(f => f?.premium !== true).length;
  }, [displayedFoods]);

  const recommendedCount = useMemo(() => {
    const list = Array.isArray(displayedFoods) ? displayedFoods : [];
    // Only count from unlocked foods for free users
    const unlocked = isPremium?.() ? list : list.filter(f => f?.premium !== true);
    return unlocked.filter(f => f?.is_recommended).length;
  }, [displayedFoods, isPremium]);

  const cautionCount = useMemo(() => {
    const list = Array.isArray(displayedFoods) ? displayedFoods : [];
    // Only count from unlocked foods for free users
    const unlocked = isPremium?.() ? list : list.filter(f => f?.premium !== true);
    return unlocked.filter(f => f?.should_limit).length;
  }, [displayedFoods, isPremium]);

  const hasPersonalization = user && ((user?.dietaryRestrictions?.length || 0) > 0 || user?.trimester);

  // Handler for when user clicks a locked food
  const handleLockedFoodClick = () => {
    // Navigate to premium page using React Router
    navigate('/premium');
  };

  // Function to check if a specific food is locked (for FoodGrid)
  // Uses the premium field from the API
  const isFoodLocked = (food) => {
    if (isPremium?.()) return false;
    return food?.premium === true;
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-6" data-testid="home-page">
      <div className="space-y-4 mb-6">
        <h2 className="text-2xl font-bold text-stone-800">
          Pregnancy Nutrition Guide
        </h2>
        <p className="text-stone-600 text-sm">
          Educational reference information about foods during pregnancy
        </p>
        <Disclaimer />
      </div>

      {/* Error Banner - shown when API fails */}
      {error && (
        <div className="mb-6 bg-amber-50 border border-amber-200 rounded-xl p-4" data-testid="error-banner">
          <p className="text-amber-700 text-sm">{error}</p>
        </div>
      )}

      {/* Daily Tip */}
      <DailyTip />

      {/* Personalization Banner */}
      {hasPersonalization && recommendations && (
        <div className="mb-6 space-y-3">
          {/* Trimester Info */}
          {recommendations?.trimester_info && (
            <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <Sparkles className="text-emerald-600 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h3 className="font-semibold text-emerald-800">
                    {recommendations.trimester_info?.name || 'Trimester Info'}
                  </h3>
                  <p className="text-sm text-emerald-700 mt-1">
                    Focus on: {(recommendations.trimester_info?.priority_nutrients || []).slice(0, 4).join(', ') || 'key nutrients'}
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Health Conditions Info */}
          {recommendations?.conditions_info?.length > 0 && (
            <div className="bg-blue-50 border border-blue-200 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <Info className="text-blue-600 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h3 className="font-semibold text-blue-800">
                    Personalized for Your Needs
                  </h3>
                  <p className="text-sm text-blue-700 mt-1">
                    {(Array.isArray(recommendations?.conditions_info) ? recommendations.conditions_info : []).map(c => c?.description).filter(Boolean).join('. ') || 'Based on your health profile'}
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Quick Stats */}
          <div className="flex gap-3">
            {recommendedCount > 0 && (
              <div className="flex items-center gap-2 bg-emerald-100 text-emerald-700 px-3 py-1.5 rounded-full text-sm">
                <Sparkles size={14} />
                {recommendedCount} recommended
              </div>
            )}
            {cautionCount > 0 && (
              <div className="flex items-center gap-2 bg-amber-100 text-amber-700 px-3 py-1.5 rounded-full text-sm">
                <AlertTriangle size={14} />
                {cautionCount} foods to limit
              </div>
            )}
          </div>
        </div>
      )}

      <div className="space-y-4 mb-6">
        <SearchBar
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search foods..."
        />

        <CategoryFilter
          categories={categories}
          selected={selectedCategory}
          onSelect={setSelectedCategory}
        />

        <SafetyFilter
          selected={selectedSafety}
          onSelect={setSelectedSafety}
        />

        {/* Toggle Personalization */}
        {hasPersonalization && (
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowPersonalized(!showPersonalized)}
              className={`text-sm px-3 py-1.5 rounded-full transition-colors ${
                showPersonalized 
                  ? 'bg-emerald-600 text-white' 
                  : 'bg-stone-100 text-stone-600'
              }`}
            >
              {showPersonalized ? 'Personalized View' : 'Show All Foods'}
            </button>
          </div>
        )}
      </div>

      <div className="mb-4">
        <p className="text-sm text-stone-500">
          {isPremium?.() 
            ? `Showing ${displayedFoods.length} foods`
            : `${freeFoodsCount} free foods · ${premiumFoodsCount} premium foods`
          }
        </p>
      </div>

      <FoodGrid 
        foods={displayedFoods} 
        loading={loading}
        isLockedFn={isFoodLocked}
        onLockedClick={handleLockedFoodClick}
      />

      {/* Premium Upsell Banner for Free Users */}
      {!isPremium?.() && premiumFoodsCount > 0 && (
        <div className="mt-6 bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-200 rounded-xl p-6 text-center">
          <Lock className="text-amber-600 mx-auto mb-3" size={28} />
          <h3 className="font-semibold text-amber-800 mb-2">
            Unlock {premiumFoodsCount} Premium Foods
          </h3>
          <p className="text-amber-700 text-sm mb-4">
            Get answers to common questions about Energy Drinks, High Mercury Fish, Deli Meats, and more.
          </p>
          <Link
            to="/premium"
            className="inline-block bg-amber-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-amber-700 transition-colors"
            data-testid="home-upgrade-premium-btn"
          >
            Unlock All Foods - $1.99
          </Link>
        </div>
      )}
    </div>
  );
}
