import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Check, Sparkles, Shield, Apple, RefreshCw, Loader } from 'lucide-react';
import { Capacitor } from '@capacitor/core';
import { useUser } from '../context/UserContext';
import iapService from '../services/InAppPurchase';

// Detect platform for UI customization
const getPlatform = () => {
  if (typeof window === 'undefined') return 'web';
  if (window.location.protocol === 'capacitor:') {
    // Check Capacitor platform
    try {
      const platform = Capacitor.getPlatform();
      if (platform === 'ios') return 'ios';
      if (platform === 'android') return 'android';
    } catch (e) {}
  }
  return 'web';
};

export default function PremiumPage() {
  const navigate = useNavigate();
  const userContext = useUser();
  // Safely destructure with fallbacks to prevent crashes during navigation
  const isPremium = userContext?.isPremium || (() => false);
  const updateUser = userContext?.updateUser || (() => {});
  const clearUser = userContext?.clearUser || (() => {});
  
  const [loading, setLoading] = useState(false);
  const [restoring, setRestoring] = useState(false);
  const [price, setPrice] = useState('$1.99');
  const [error, setError] = useState(null);
  const [iapReady, setIapReady] = useState(false);
  const [platform, setPlatform] = useState('web');
  const [isValidUser, setIsValidUser] = useState(null); // null = checking, true = valid, false = invalid

  // Detect platform on mount
  useEffect(() => {
    setPlatform(getPlatform());
  }, []);

  // Check if user has a valid session - if not, redirect to onboarding
  // Also check if disclaimer was accepted THIS SESSION (required on every app launch)
  useEffect(() => {
    // CRITICAL: Check disclaimer acceptance first
    const disclaimerAcceptedThisSession = sessionStorage.getItem('disclaimer_accepted_session') === 'true';
    if (!disclaimerAcceptedThisSession) {
      // Disclaimer not accepted - redirect to onboarding
      setIsValidUser(false);
      navigate('/onboarding', { replace: true });
      return;
    }
    
    const userStr = localStorage.getItem('whattoeat_user');
    if (!userStr) {
      // No user in storage - set invalid flag and redirect
      setIsValidUser(false);
      navigate('/onboarding', { replace: true });
      return;
    }
    
    // Parse user and check if they have basic info
    try {
      const userData = JSON.parse(userStr);
      if (!userData?.email && !userData?.id) {
        // Invalid user data - set invalid flag and redirect
        setIsValidUser(false);
        navigate('/onboarding', { replace: true });
        return;
      }
      setIsValidUser(true);
    } catch (e) {
      // Invalid JSON - set invalid flag and redirect
      setIsValidUser(false);
      navigate('/onboarding', { replace: true });
      return;
    }
    
    // Clear navigation flag when Premium page loads successfully
    sessionStorage.removeItem('navigateToPremium');
  }, [navigate]);

  // Initialize In-App Purchase
  useEffect(() => {
    const initIAP = async () => {
      const ready = await iapService.initialize();
      setIapReady(ready);
      
      if (ready) {
        const productPrice = iapService.getPrice();
        setPrice(productPrice);
        
        // Check if already premium
        if (iapService.isPremiumActive()) {
          updateUser({ isPremium: true });
        }
      }
    };

    initIAP();

    // Set up purchase update callback
    iapService.setUpdateCallback((event) => {
      if (event.type === 'verified' || event.type === 'finished') {
        updateUser({ isPremium: true, premiumPurchasedAt: new Date().toISOString() });
        navigate('/');
      } else if (event.type === 'error') {
        setError(event.error?.message || 'Purchase failed');
        setLoading(false);
      } else if (event.type === 'productUpdated') {
        const productPrice = iapService.getPrice();
        setPrice(productPrice);
      }
    });
  }, [updateUser, navigate]);

  const handleSubscribe = async () => {
    setLoading(true);
    setError(null);
    
    const result = await iapService.purchase();
    
    if (!result.success) {
      setError(result.error);
      setLoading(false);
    }
    // Success is handled by the callback
  };

  const handleRestore = async () => {
    setRestoring(true);
    setError(null);
    
    const result = await iapService.restorePurchases();
    
    if (result.success) {
      // Check if premium is now active
      setTimeout(() => {
        if (iapService.isPremiumActive()) {
          updateUser({ isPremium: true });
          navigate('/');
        } else {
          setError('No previous purchases found');
        }
        setRestoring(false);
      }, 2000);
    } else {
      setError(result.error);
      setRestoring(false);
    }
  };

  const handleCancel = () => {
    // Clear user data and return to onboarding to start fresh
    clearUser();
    navigate('/onboarding', { replace: true });
  };

  const handleContinueFree = () => {
    // CRITICAL: Update localStorage FIRST (synchronous) before any async operations
    const userStr = localStorage.getItem('whattoeat_user');
    let userData = null;
    
    if (userStr) {
      try {
        userData = JSON.parse(userStr);
        userData.onboardingCompleted = true;
        localStorage.setItem('whattoeat_user', JSON.stringify(userData));
        console.log('handleContinueFree: Updated localStorage with onboardingCompleted=true');
      } catch (e) {
        console.error('Error updating user data:', e);
      }
    }
    
    // Set session flags for ProtectedRoute and PremiumPage
    sessionStorage.setItem('continuedFromPremium', 'true');
    sessionStorage.setItem('disclaimer_accepted_session', 'true');
    
    // Update React context (this is async internally)
    updateUser({ onboardingCompleted: true });
    
    // Navigate to home
    console.log('handleContinueFree: Navigating to /home');
    navigate('/home', { replace: true });
  };

  const features = [
    'Curated food ideas for each trimester (based on general public health guidelines)',
    'Smart filter to browse foods by trimester stage',
    'Expanded food database with detailed nutritional notes',
    'Weekly pregnancy nutrition tip library',
    'Priority support',
  ];

  // Show loading state while validating user (null = checking)
  // Also show loading if validation failed (will redirect shortly)
  if (isValidUser !== true) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-emerald-50 to-white flex items-center justify-center p-4">
        <div className="w-8 h-8 border-3 border-emerald-600 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  // If already premium, redirect to home
  if (isPremium()) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-emerald-50 to-white flex items-center justify-center p-4">
        <div className="text-center">
          <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <Check className="text-emerald-600" size={32} />
          </div>
          <h2 className="text-xl font-semibold text-stone-800 mb-2">You're Premium!</h2>
          <p className="text-stone-600 mb-4">You have access to all premium features.</p>
          <button
            onClick={() => navigate('/')}
            className="px-6 py-3 bg-emerald-600 text-white rounded-xl font-medium"
          >
            Go to Home
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-emerald-50 to-white">
      <div className="max-w-md mx-auto px-4 py-8 pb-32">
        
        {/* Back/Cancel Button - Returns to onboarding to cancel payment flow */}
        <button
          onClick={handleCancel}
          className="flex items-center gap-2 text-stone-600 hover:text-stone-800 mb-4 transition-colors"
          data-testid="back-btn"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M19 12H5M12 19l-7-7 7-7"/>
          </svg>
          Cancel
        </button>
        
        {/* Header */}
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-gradient-to-br from-emerald-400 to-emerald-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg">
            <Sparkles className="text-white" size={32} />
          </div>
          <h1 className="text-2xl font-bold text-stone-800 mb-2">
            Unlock Premium Pregnancy Nutrition
          </h1>
          <p className="text-stone-600">
            Expand your pregnancy nutrition reference library
          </p>
        </div>

        {/* Features */}
        <div className="bg-white rounded-2xl p-6 shadow-sm border border-stone-100 mb-6">
          <h3 className="font-semibold text-stone-800 mb-4">Premium Features</h3>
          <ul className="space-y-3">
            {features.map((feature, index) => (
              <li key={index} className="flex items-start gap-3">
                <div className="w-5 h-5 bg-emerald-100 rounded-full flex items-center justify-center flex-shrink-0 mt-0.5">
                  <Check className="text-emerald-600" size={12} />
                </div>
                <span className="text-stone-700 text-sm">{feature}</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Subscription Card */}
        <div className="bg-gradient-to-br from-emerald-500 to-emerald-600 rounded-2xl p-6 text-white mb-6 shadow-lg">
          <div className="flex items-center justify-between mb-4">
            <div>
              <p className="text-emerald-100 text-sm">Premium Access</p>
              <p className="text-3xl font-bold">{price}</p>
              <p className="text-emerald-100 text-sm mt-1">for your entire pregnancy</p>
            </div>
            {/* Platform-specific icon */}
            {platform === 'android' ? (
              // Google Play icon
              <svg viewBox="0 0 24 24" width="36" height="36" className="text-emerald-100" fill="currentColor">
                <path d="M3.609 1.814L13.792 12 3.61 22.186a.996.996 0 0 1-.61-.92V2.734a1 1 0 0 1 .609-.92zm10.89 10.893l2.302 2.302-10.937 6.333 8.635-8.635zm3.199-3.198l2.807 1.626a1 1 0 0 1 0 1.73l-2.808 1.626L15.206 12l2.492-2.491zM5.864 2.658L16.8 8.99l-2.302 2.302-8.634-8.634z"/>
              </svg>
            ) : (
              <Apple size={32} className="text-emerald-100" />
            )}
          </div>
          <p className="text-emerald-100 text-xs">
            {platform === 'android' 
              ? 'One-time purchase via Google Play • 12 months access • No subscription'
              : 'One-time purchase • 12 months access • No subscription'
            }
          </p>
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-3 mb-4">
            <p className="text-red-600 text-sm text-center">{error}</p>
          </div>
        )}

        {/* Primary CTA */}
        <button
          onClick={handleSubscribe}
          disabled={loading}
          className="w-full py-4 bg-emerald-600 text-white rounded-xl font-semibold text-lg hover:bg-emerald-700 transition-colors flex items-center justify-center gap-3 disabled:opacity-50 mb-3"
          data-testid="subscribe-btn"
        >
          {loading ? (
            <>
              <Loader className="animate-spin" size={20} />
              Processing...
            </>
          ) : (
            <>
              {platform === 'android' ? (
                // Google Play icon for button
                <svg viewBox="0 0 24 24" width="22" height="22" fill="currentColor">
                  <path d="M3.609 1.814L13.792 12 3.61 22.186a.996.996 0 0 1-.61-.92V2.734a1 1 0 0 1 .609-.92zm10.89 10.893l2.302 2.302-10.937 6.333 8.635-8.635zm3.199-3.198l2.807 1.626a1 1 0 0 1 0 1.73l-2.808 1.626L15.206 12l2.492-2.491zM5.864 2.658L16.8 8.99l-2.302 2.302-8.634-8.634z"/>
                </svg>
              ) : (
                <Apple size={20} />
              )}
              {platform === 'android' ? 'Get Premium with Google Play' : 'Get Premium for $1.99'}
            </>
          )}
        </button>

        {/* Secondary CTA */}
        <button
          onClick={handleContinueFree}
          className="w-full py-3 text-stone-600 font-medium hover:text-stone-800 transition-colors"
          data-testid="continue-free-btn"
        >
          Continue with Free Version
        </button>

        {/* Restore Purchases */}
        <button
          onClick={handleRestore}
          disabled={restoring}
          className="w-full py-3 text-emerald-600 font-medium flex items-center justify-center gap-2 mt-2"
          data-testid="restore-btn"
        >
          {restoring ? (
            <>
              <Loader className="animate-spin" size={16} />
              Restoring...
            </>
          ) : (
            <>
              <RefreshCw size={16} />
              Restore Purchases
            </>
          )}
        </button>

        {/* Legal Links */}
        <div className="flex items-center justify-center gap-4 mt-6 text-xs text-stone-500">
          <Link to="/terms" className="hover:text-stone-700">Terms of Service</Link>
          <span>•</span>
          <Link to="/privacy" className="hover:text-stone-700">Privacy Policy</Link>
        </div>

        {/* Purchase Disclosure */}
        <p className="text-xs text-stone-400 text-center mt-4 px-4 leading-relaxed">
          {platform === 'android' 
            ? 'This is a one-time purchase that provides 12 months of premium access. No automatic renewal. You can restore your purchase on any device using the same Google Play account.'
            : 'This is a one-time purchase that provides 12 months of premium access. No automatic renewal. You can restore your purchase on any device using the same Apple ID.'
          }
        </p>

        {/* Premium Clarification Note */}
        <div className="bg-stone-50 border border-stone-200 rounded-xl p-4 mt-4">
          <p className="text-xs text-stone-500 text-center leading-relaxed">
            <strong>Note:</strong> Premium provides access to expanded educational content and enhanced browsing tools. All information remains general reference material. Always consult a healthcare provider for personal medical advice.
          </p>
        </div>

        {/* Copyright */}
        <p className="text-xs text-stone-400 text-center mt-4">
          © PenX Technologies
        </p>
      </div>
    </div>
  );
}
