/**
 * Apple Sign In Service for iOS
 * Uses @capawesome/capacitor-apple-sign-in plugin for native iOS authentication
 */

import { Capacitor } from '@capacitor/core';

// Dynamically import the plugin to avoid issues on web
let AppleSignIn = null;

// Initialize plugin (only on iOS)
const initPlugin = async () => {
  if (Capacitor.getPlatform() === 'ios' && !AppleSignIn) {
    try {
      const module = await import('@capawesome/capacitor-apple-sign-in');
      AppleSignIn = module.AppleSignIn;
      return true;
    } catch (err) {
      console.log('[AppleSignIn] Plugin not available:', err.message);
      return false;
    }
  }
  return AppleSignIn !== null;
};

/**
 * Check if Apple Sign In is available on current platform
 */
export const isAppleSignInAvailable = () => {
  return Capacitor.getPlatform() === 'ios';
};

/**
 * Perform Apple Sign In
 * Returns user data including identityToken for backend verification
 */
export const signInWithApple = async () => {
  if (!isAppleSignInAvailable()) {
    throw new Error('Apple Sign In is only available on iOS');
  }

  const initialized = await initPlugin();
  if (!initialized || !AppleSignIn) {
    throw new Error('Apple Sign In plugin not initialized');
  }

  try {
    // Request sign in with email and full name scopes
    const result = await AppleSignIn.signIn({
      scopes: ['email', 'fullName'],
    });

    console.log('[AppleSignIn] Success:', {
      user: result.user,
      email: result.email,
      hasIdentityToken: !!result.identityToken,
    });

    // Return formatted result
    return {
      // Apple's stable user identifier (never changes)
      appleUserId: result.user,
      // Email (only provided on first sign-in, may be null on subsequent logins)
      email: result.email || null,
      // Full name components (only provided on first sign-in)
      fullName: result.givenName || result.familyName 
        ? `${result.givenName || ''} ${result.familyName || ''}`.trim()
        : null,
      givenName: result.givenName || null,
      familyName: result.familyName || null,
      // Identity token for backend verification (JWT signed by Apple)
      identityToken: result.identityToken,
      // Authorization code for server-side token exchange
      authorizationCode: result.authorizationCode,
    };
  } catch (err) {
    console.error('[AppleSignIn] Error:', err);
    
    // Handle user cancellation gracefully
    if (err.message?.includes('canceled') || err.code === 'ERR_CANCELED') {
      throw new Error('Sign in cancelled');
    }
    
    throw new Error(err.message || 'Apple Sign In failed');
  }
};

export default {
  isAppleSignInAvailable,
  signInWithApple,
};
