import React, { useState } from 'react';
import { Search, AlertCircle, BookOpen, ArrowLeft, Lock } from 'lucide-react';
import { Link } from 'react-router-dom';
import { topicsApi } from '../api';
import { Disclaimer } from '../components/common/Filters';
import { useUser } from '../context/UserContext';

export default function TopicsPage() {
  const { isPremium } = useUser();
  const [query, setQuery] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  // Free users get limited topics, premium gets all
  const allTopics = [
    'Folate',
    'Iron',
    'Calcium',
    'Omega-3',
    'Protein',
    'Vitamin D',
    'Morning sickness',
    'Hydration',
  ];
  
  const freeTopics = ['Folate', 'Iron', 'Calcium']; // 3 topics for free users
  const suggestedTopics = isPremium() ? allTopics : freeTopics;
  const lockedTopics = isPremium() ? [] : allTopics.filter(t => !freeTopics.includes(t));

  const handleSearch = async (e, searchQuery = null) => {
    if (e) e.preventDefault();
    const queryToSearch = searchQuery || query;
    if (!queryToSearch.trim()) return;

    // Check if free user is trying to access premium topic
    if (!isPremium() && lockedTopics.some(t => t.toLowerCase() === queryToSearch.toLowerCase())) {
      setSearched(true);
      setResult({ isPremiumLocked: true });
      return;
    }

    setLoading(true);
    setSearched(true);
    try {
      const response = await topicsApi.search(queryToSearch);
      setResult(response.data);
    } catch (error) {
      console.error('Error searching topics:', error);
      setResult(null);
    } finally {
      setLoading(false);
    }
  };

  const handleSuggestedTopicClick = (topic) => {
    setQuery(topic);
    handleSearch(null, topic);
  };

  const handleBackToTopics = () => {
    setSearched(false);
    setResult(null);
    setQuery('');
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-6" data-testid="topics-page">
      <div className="space-y-4 mb-6">
        <h2 className="text-2xl font-bold text-stone-800">Nutrition Topics</h2>
        <p className="text-stone-600 text-sm">
          Search for educational information about pregnancy nutrition topics
        </p>
        <Disclaimer />
        
        {/* Topics Disclaimer Banner */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
          <p className="text-xs text-blue-700">
            Browse general nutrition information compiled from public health sources. Always verify with your healthcare provider.
          </p>
        </div>
      </div>

      {/* Back to Topics Button - shown when viewing results */}
      {searched && (
        <button
          onClick={handleBackToTopics}
          className="inline-flex items-center gap-2 text-emerald-600 mb-4 hover:text-emerald-700 transition-colors"
          data-testid="back-to-topics-btn"
        >
          <ArrowLeft size={20} />
          Back to Topics
        </button>
      )}

      {/* Search Form */}
      <form onSubmit={handleSearch} className="mb-4">
        <div className="flex gap-2">
          <div className="relative flex-1">
            <Search
              size={18}
              className="absolute left-3 top-1/2 -translate-y-1/2 text-stone-400"
            />
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search nutrition topics..."
              className="w-full pl-10 pr-4 py-3 bg-white border border-stone-200 rounded-xl text-stone-800 placeholder-stone-400 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent"
              data-testid="topics-search-input"
            />
          </div>
          <button
            type="submit"
            disabled={loading || !query.trim()}
            className="px-6 py-3 bg-emerald-600 text-white rounded-xl font-medium hover:bg-emerald-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            data-testid="topics-search-btn"
          >
            {loading ? 'Searching...' : 'Search'}
          </button>
        </div>
      </form>

      {/* Search Results Disclaimer */}
      {searched && (
        <p className="text-xs text-stone-500 mb-4 italic">
          Search results are generated from our static educational database. No AI generates responses to your specific questions.
        </p>
      )}

      {/* Suggested Topics */}
      {!searched && (
        <div className="mb-6">
          <h3 className="text-sm font-medium text-stone-500 mb-3">
            {isPremium() ? 'All Topics' : 'Free Topics'}
          </h3>
          <div className="flex flex-wrap gap-2">
            {suggestedTopics.map((topic) => (
              <button
                key={topic}
                onClick={() => handleSuggestedTopicClick(topic)}
                className="px-3 py-1.5 bg-stone-100 text-stone-600 rounded-full text-sm hover:bg-stone-200 transition-colors"
                data-testid={`suggested-topic-${topic.toLowerCase()}`}
              >
                {topic}
              </button>
            ))}
          </div>
          
          {/* Locked Topics for Free Users */}
          {!isPremium() && lockedTopics.length > 0 && (
            <div className="mt-4">
              <h3 className="text-sm font-medium text-stone-400 mb-3 flex items-center gap-2">
                <Lock size={14} />
                Premium Topics
              </h3>
              <div className="flex flex-wrap gap-2">
                {lockedTopics.map((topic) => (
                  <Link
                    key={topic}
                    to="/premium"
                    className="px-3 py-1.5 bg-stone-50 text-stone-400 rounded-full text-sm border border-stone-200 flex items-center gap-1.5 hover:bg-amber-50 hover:text-amber-600 hover:border-amber-200 transition-colors"
                    data-testid={`locked-topic-${topic.toLowerCase()}`}
                  >
                    <Lock size={12} />
                    {topic}
                  </Link>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Results */}
      {searched && result && (
        <div className="space-y-4" data-testid="topics-result">
          {/* Premium Locked Notice */}
          {result.isPremiumLocked && (
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-6 text-center">
              <Lock className="text-amber-600 mx-auto mb-3" size={32} />
              <h3 className="font-semibold text-amber-800 mb-2">Premium Topic</h3>
              <p className="text-amber-700 text-sm mb-4">
                This topic is available for premium users. Upgrade to access all nutrition topics and foods.
              </p>
              <Link
                to="/premium"
                className="inline-block bg-amber-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-amber-700 transition-colors"
                data-testid="upgrade-premium-btn"
              >
                Upgrade to Premium
              </Link>
            </div>
          )}

          {/* Symptom Detection Warning */}
          {result.is_symptom_detected && (
            <div className="bg-red-50 border border-red-200 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <AlertCircle className="text-red-600 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h3 className="font-semibold text-red-800 mb-1">Medical Attention Needed</h3>
                  <p className="text-red-700 text-sm">{result.information}</p>
                  {result.disclaimer && (
                    <p className="text-red-600 text-xs mt-2">{result.disclaimer}</p>
                  )}
                </div>
              </div>
            </div>
          )}

          {/* Personal Question Notice */}
          {result.is_personal_question && (
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <AlertCircle className="text-amber-600 flex-shrink-0 mt-0.5" size={20} />
                <div>
                  <h3 className="font-semibold text-amber-800 mb-1">Personal Guidance Needed</h3>
                  <p className="text-amber-700 text-sm">{result.information}</p>
                </div>
              </div>
            </div>
          )}

          {/* Normal Result */}
          {!result.is_symptom_detected && !result.is_personal_question && !result.isPremiumLocked && (
            <div className="bg-white border border-stone-200 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <BookOpen className="text-emerald-600 flex-shrink-0 mt-0.5" size={20} />
                <div className="flex-1">
                  {result.topic_matched && (
                    <span className="inline-block bg-emerald-100 text-emerald-700 text-xs px-2 py-1 rounded-full mb-2">
                      Topic: {result.topic_matched}
                    </span>
                  )}
                  <p className="text-stone-700 whitespace-pre-line">{result.information}</p>
                  
                  {/* Sources - Updated format with specific publications */}
                  <div className="mt-4 pt-4 border-t border-stone-100">
                    <p className="text-xs font-medium text-stone-600 mb-2">Sources:</p>
                    <ul className="text-xs text-stone-500 space-y-1">
                      <li>• WHO: Antenatal care recommendations for healthy pregnancy (2023)</li>
                      <li>• CDC: Nutrition During Pregnancy Fact Sheet</li>
                      <li>• NHS: Vitamins and nutrition in pregnancy guide</li>
                      <li>• ACOG: Nutrition During Pregnancy Practice Bulletin</li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Disclaimer */}
          {result.disclaimer && !result.is_symptom_detected && (
            <p className="text-xs text-stone-500 italic">{result.disclaimer}</p>
          )}
        </div>
      )}

      {/* No Results */}
      {searched && !result && !loading && (
        <div className="text-center py-12 text-stone-500">
          No information found for "{query}"
        </div>
      )}
    </div>
  );
}
