import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { ArrowLeft, ChevronDown, ChevronUp, ExternalLink, Sparkles, AlertTriangle, Check, Info, ShieldCheck, Utensils, Clock, AlertCircle, Lock, Share2, CheckCircle } from 'lucide-react';
import { foodsApi } from '../api';
import { SafetyBadge, NutrientTag } from '../components/food/FoodCard';
import { Disclaimer } from '../components/common/Filters';
import { useUser } from '../context/UserContext';
import { toast } from 'sonner';

export default function FoodDetailPage() {
  const { id } = useParams();
  const { getTrimester, getDietaryRestrictions, user } = useUser();
  const [food, setFood] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showSources, setShowSources] = useState(false);

  const isPremiumUser = user?.isPremium === true;
  const [shareSuccess, setShareSuccess] = useState(false);

  // Generate shareable text summary
  const generateShareText = () => {
    if (!food) return '';
    
    const safetyEmoji = food.safety_level === 'safe' ? '✅' : food.safety_level === 'limit' ? '⚠️' : '🚫';
    const safetyLabel = food.safety_level === 'safe' ? 'Generally Safe' : food.safety_level === 'limit' ? 'Limit Consumption' : 'Avoid';
    
    // Check if content is locked (premium food and non-premium user)
    const foodIsLocked = food.premium === true && !isPremiumUser;
    
    let text = `${safetyEmoji} ${food.name} during pregnancy\n`;
    text += `━━━━━━━━━━━━━━━━━━\n`;
    text += `Status: ${safetyLabel}\n`;
    
    if (Array.isArray(food.nutrients) && food.nutrients.length > 0) {
      text += `\n🥗 Key Nutrients:\n`;
      text += food.nutrients.slice(0, 4).map(n => `• ${n}`).join('\n');
    }
    
    if (!foodIsLocked && Array.isArray(food.consumption_guidance) && food.consumption_guidance.length > 0) {
      text += `\n\n📋 Guidance:\n`;
      text += food.consumption_guidance.slice(0, 2).map(g => `• ${g}`).join('\n');
    }
    
    if (!foodIsLocked && Array.isArray(food.precautions) && food.precautions.length > 0) {
      text += `\n\n⚠️ Note:\n`;
      text += food.precautions.slice(0, 2).map(p => `• ${p}`).join('\n');
    }
    
    text += `\n\n━━━━━━━━━━━━━━━━━━`;
    text += `\nSource: WHO, CDC, NHS, ACOG`;
    text += `\nShared via WhatToEat App`;
    
    return text;
  };

  // Handle share action
  const handleShare = async () => {
    const shareText = generateShareText();
    
    // Try native share API first (works great on iOS/mobile)
    if (navigator.share) {
      try {
        await navigator.share({
          title: `${food.name} - Pregnancy Food Safety`,
          text: shareText,
        });
        setShareSuccess(true);
        setTimeout(() => setShareSuccess(false), 2000);
        return;
      } catch (err) {
        // User cancelled or share failed, fall back to clipboard
        if (err.name !== 'AbortError') {
          console.log('Native share failed, using clipboard');
        }
      }
    }
    
    // Fallback: copy to clipboard
    try {
      await navigator.clipboard.writeText(shareText);
      toast.success('Copied to clipboard! Ready to paste and share.');
      setShareSuccess(true);
      setTimeout(() => setShareSuccess(false), 2000);
    } catch (err) {
      toast.error('Could not copy to clipboard');
    }
  };

  useEffect(() => {
    async function fetchFood() {
      try {
        const trimester = getTrimester?.();
        const healthConditions = getDietaryRestrictions?.() || [];
        
        if (healthConditions.length > 0 || trimester) {
          const response = await foodsApi.getPersonalized(healthConditions, trimester);
          const foods = Array.isArray(response?.data?.foods) ? response.data.foods : [];
          const foundFood = foods.find(f => f.id === id);
          if (foundFood) {
            setFood(foundFood);
          } else {
            const regularResponse = await foodsApi.getById(id);
            setFood(regularResponse?.data || null);
          }
        } else {
          const response = await foodsApi.getById(id);
          setFood(response?.data || null);
        }
      } catch (err) {
        setError('Food not found');
        console.error('Error fetching food:', err);
      } finally {
        setLoading(false);
      }
    }
    fetchFood();
  }, [id, getTrimester, getDietaryRestrictions]);

  if (loading) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-stone-200 rounded w-1/4" />
          <div className="h-12 bg-stone-200 rounded w-3/4" />
          <div className="h-32 bg-stone-200 rounded" />
        </div>
      </div>
    );
  }

  if (error || !food) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-6">
        <Link to="/" className="inline-flex items-center gap-2 text-emerald-600 mb-6">
          <ArrowLeft size={20} />
          Back to Home
        </Link>
        <div className="text-center py-12">
          <p className="text-stone-500">{error || 'Food not found'}</p>
        </div>
      </div>
    );
  }

  const isRecommended = food.is_recommended;
  const shouldLimit = food.should_limit;
  const isPremiumFood = food.premium === true;
  const isLocked = isPremiumFood && !isPremiumUser;

  // Helper to render bullet list
  const BulletList = ({ items, icon: Icon, iconColor = "text-stone-400" }) => {
    if (!Array.isArray(items) || items.length === 0) return null;
    return (
      <ul className="space-y-2">
        {items.map((item, index) => (
          <li key={index} className="flex items-start gap-2">
            <Icon size={16} className={`${iconColor} flex-shrink-0 mt-0.5`} />
            <span className="text-stone-700 text-sm">{item}</span>
          </li>
        ))}
      </ul>
    );
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-6" data-testid="food-detail-page">
      <div className="flex items-center justify-between mb-6">
        <Link 
          to="/" 
          className="inline-flex items-center gap-2 text-emerald-600 hover:text-emerald-700"
          data-testid="back-btn"
        >
          <ArrowLeft size={20} />
          Back to Home
        </Link>
        
        {/* Share Button */}
        <button
          onClick={handleShare}
          className={`inline-flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all ${
            shareSuccess 
              ? 'bg-emerald-100 text-emerald-700' 
              : 'bg-stone-100 text-stone-700 hover:bg-stone-200'
          }`}
          data-testid="share-btn"
        >
          {shareSuccess ? (
            <>
              <CheckCircle size={18} />
              Shared!
            </>
          ) : (
            <>
              <Share2 size={18} />
              Share
            </>
          )}
        </button>
      </div>

      <div className="space-y-6">
        {/* Header with Safety Badge */}
        <div className="bg-white rounded-xl p-4 border border-stone-200">
          <div className="flex items-start justify-between gap-4 mb-2">
            <div>
              <h1 className="text-2xl font-bold text-stone-800" data-testid="food-name">{food.name}</h1>
              <p className="text-stone-500 text-sm mt-1">{food.category}</p>
            </div>
            <SafetyBadge level={food.safety_level} size="md" />
          </div>
          
          {/* Premium Badge */}
          {isPremiumFood && (
            <div className="mt-3 inline-flex items-center gap-1.5 px-2 py-1 bg-amber-50 text-amber-700 text-xs rounded-full">
              <Lock size={12} />
              Premium Content
            </div>
          )}
        </div>

        {/* Personalization Banners */}
        {isRecommended && (
          <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4">
            <div className="flex items-start gap-3">
              <Sparkles className="text-emerald-600 flex-shrink-0 mt-0.5" size={20} />
              <div>
                <h3 className="font-semibold text-emerald-800">Recommended for You</h3>
                {Array.isArray(food.recommendation_reasons) && food.recommendation_reasons.length > 0 && (
                  <div className="flex flex-wrap gap-2 mt-2">
                    {food.recommendation_reasons.map((reason, idx) => (
                      <span key={idx} className="inline-flex items-center gap-1 text-sm bg-emerald-100 text-emerald-700 px-2 py-1 rounded-full">
                        <Check size={12} />
                        {reason}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {shouldLimit && (
          <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
            <div className="flex items-start gap-3">
              <AlertTriangle className="text-amber-600 flex-shrink-0 mt-0.5" size={20} />
              <div>
                <h3 className="font-semibold text-amber-800">Consider Limiting</h3>
                {Array.isArray(food.caution_reasons) && food.caution_reasons.length > 0 && (
                  <div className="flex flex-wrap gap-2 mt-2">
                    {food.caution_reasons.map((reason, idx) => (
                      <span key={idx} className="inline-flex items-center gap-1 text-sm bg-amber-100 text-amber-700 px-2 py-1 rounded-full">
                        <Info size={12} />
                        {reason}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Locked Content Notice for Free Users */}
        {isLocked && (
          <div className="bg-stone-100 border border-stone-300 rounded-xl p-4">
            <div className="flex items-start gap-3">
              <Lock className="text-stone-500 flex-shrink-0 mt-0.5" size={20} />
              <div>
                <h3 className="font-semibold text-stone-700">Premium Content</h3>
                <p className="text-stone-600 text-sm mt-1">
                  Detailed guidance for this food is available with Premium. 
                  Upgrade to access preparation tips, consumption guidance, and precautions.
                </p>
                <Link 
                  to="/premium" 
                  className="inline-flex items-center gap-2 mt-3 px-4 py-2 bg-emerald-600 text-white text-sm font-medium rounded-lg hover:bg-emerald-700 transition-colors"
                  data-testid="upgrade-btn"
                >
                  <Lock size={14} />
                  Unlock Premium
                </Link>
              </div>
            </div>
          </div>
        )}

        {/* Nutritional Benefits */}
        {Array.isArray(food.nutrients) && food.nutrients.length > 0 && (
          <div className="bg-white rounded-xl p-4 border border-stone-200" data-testid="nutrients-section">
            <div className="flex items-center gap-2 mb-3">
              <ShieldCheck size={18} className="text-emerald-600" />
              <h2 className="font-semibold text-stone-800">Nutritional Benefits</h2>
            </div>
            <div className="flex flex-wrap gap-2">
              {food.nutrients.map((nutrient) => (
                <NutrientTag key={nutrient} nutrient={nutrient} />
              ))}
            </div>
          </div>
        )}

        {/* Recommended Consumption - Only show full content for premium users or free foods */}
        {Array.isArray(food.consumption_guidance) && food.consumption_guidance.length > 0 && (
          <div className={`bg-white rounded-xl p-4 border border-stone-200 ${isLocked ? 'opacity-60' : ''}`} data-testid="consumption-section">
            <div className="flex items-center gap-2 mb-3">
              <Clock size={18} className="text-blue-600" />
              <h2 className="font-semibold text-stone-800">Recommended Consumption</h2>
            </div>
            {isLocked ? (
              <div className="flex items-center gap-2 text-stone-500 text-sm">
                <Lock size={14} />
                <span>Upgrade to Premium to view consumption guidance</span>
              </div>
            ) : (
              <BulletList items={food.consumption_guidance} icon={Check} iconColor="text-blue-500" />
            )}
          </div>
        )}

        {/* Preparation Tips */}
        {Array.isArray(food.preparation_tips) && food.preparation_tips.length > 0 && (
          <div className={`bg-white rounded-xl p-4 border border-stone-200 ${isLocked ? 'opacity-60' : ''}`} data-testid="preparation-section">
            <div className="flex items-center gap-2 mb-3">
              <Utensils size={18} className="text-purple-600" />
              <h2 className="font-semibold text-stone-800">Preparation Tips</h2>
            </div>
            {isLocked ? (
              <div className="flex items-center gap-2 text-stone-500 text-sm">
                <Lock size={14} />
                <span>Upgrade to Premium to view preparation tips</span>
              </div>
            ) : (
              <BulletList items={food.preparation_tips} icon={Check} iconColor="text-purple-500" />
            )}
          </div>
        )}

        {/* Precautions */}
        {Array.isArray(food.precautions) && food.precautions.length > 0 && (
          <div className={`bg-rose-50 rounded-xl p-4 border border-rose-200 ${isLocked ? 'opacity-60' : ''}`} data-testid="precautions-section">
            <div className="flex items-center gap-2 mb-3">
              <AlertCircle size={18} className="text-rose-600" />
              <h2 className="font-semibold text-rose-800">Precautions</h2>
            </div>
            {isLocked ? (
              <div className="flex items-center gap-2 text-rose-500 text-sm">
                <Lock size={14} />
                <span>Upgrade to Premium to view precautions</span>
              </div>
            ) : (
              <BulletList items={food.precautions} icon={AlertTriangle} iconColor="text-rose-500" />
            )}
          </div>
        )}

        {/* References */}
        {Array.isArray(food.sources) && food.sources.length > 0 && (
          <div className="border border-stone-200 rounded-xl overflow-hidden">
            <button
              onClick={() => setShowSources(!showSources)}
              className="w-full flex items-center justify-between p-4 bg-stone-50 hover:bg-stone-100 transition-colors"
              data-testid="sources-toggle-btn"
            >
              <span className="font-medium text-stone-700">View References</span>
              {showSources ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
            </button>
            {showSources && (
              <div className="p-4 bg-white border-t border-stone-200">
                <ul className="space-y-2">
                  {food.sources.map((source, index) => (
                    <li key={index} className="flex items-center gap-2 text-sm text-stone-600">
                      <ExternalLink size={14} className="text-stone-400" />
                      {source}
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        )}

        {/* Disclaimer */}
        <Disclaimer variant="warning" />
      </div>
    </div>
  );
}
