import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ChevronRight, FileText, Shield, HelpCircle, Crown, User, LogOut, Database, Trash2, RefreshCw } from 'lucide-react';
import { useUser } from '../context/UserContext';
import { getCacheStats, clearAllCache } from '../utils/cache';
import { authApi } from '../api';
import iapService from '../services/InAppPurchase';

export default function SettingsPage() {
  const navigate = useNavigate();
  const { user, isPremium, getPremiumExpirationDate, clearUser, getPregnancyStageLabel } = useUser();
  const [cacheStats, setCacheStats] = useState({ entryCount: 0, sizeKB: 0 });
  const [restoring, setRestoring] = useState(false);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    setCacheStats(getCacheStats());
  }, []);

  const handleClearCache = () => {
    if (window.confirm('Clear offline cache? Data will be re-downloaded next time you connect.')) {
      clearAllCache();
      setCacheStats(getCacheStats());
    }
  };

  const handleRestorePurchases = async () => {
    setRestoring(true);
    try {
      const result = await iapService.restorePurchases();
      if (result.restored) {
        alert('Your purchase has been restored!');
        window.location.reload();
      } else {
        alert('No previous purchases found.');
      }
    } catch (error) {
      alert('Unable to restore purchases. Please try again later.');
    } finally {
      setRestoring(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (window.confirm('Are you sure you want to delete your account? This will permanently remove all your data from our servers and cannot be undone.')) {
      setDeleting(true);
      try {
        // Delete account from server
        await authApi.deleteAccount();
        // Clear local data
        clearAllCache();
        clearUser();
        alert('Your account has been deleted successfully.');
        navigate('/onboarding');
      } catch (error) {
        console.error('Error deleting account:', error);
        // Even if server delete fails, clear local data
        clearAllCache();
        clearUser();
        navigate('/onboarding');
      } finally {
        setDeleting(false);
      }
    }
  };

  // Format expiration date
  const formatExpirationDate = () => {
    const expDate = getPremiumExpirationDate();
    if (!expDate) return null;
    return expDate.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  };

  // Get premium status text
  const getPremiumStatusText = () => {
    if (isPremium()) {
      const expDate = formatExpirationDate();
      return expDate ? `Access until ${expDate}` : 'Full access to all features';
    }
    return 'Unlock all features for $1.99';
  };

  const settingsItems = [
    {
      icon: Crown,
      label: isPremium() ? 'Premium Active' : 'Upgrade to Premium',
      description: getPremiumStatusText(),
      to: '/premium',
      highlight: !isPremium(),
    },
    {
      icon: FileText,
      label: 'Terms of Use',
      description: 'Read our terms and conditions',
      to: '/terms',
    },
    {
      icon: Shield,
      label: 'Privacy Policy',
      description: 'How we handle your data',
      to: '/privacy',
    },
    {
      icon: HelpCircle,
      label: 'Support',
      description: 'Get help and contact us',
      to: '/support',
    },
  ];

  return (
    <div className="max-w-4xl mx-auto px-4 py-6" data-testid="settings-page">
      <h2 className="text-2xl font-bold text-stone-800 mb-6">Settings</h2>

      {/* User Profile Card */}
      {user && (
        <div className="bg-white rounded-2xl p-5 border border-stone-200 mb-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 bg-emerald-100 rounded-xl flex items-center justify-center">
              <User className="text-emerald-600" size={28} />
            </div>
            <div className="flex-1">
              <div className="flex items-center gap-2">
                <h3 className="font-semibold text-stone-800">Your Profile</h3>
                {isPremium() && (
                  <span className="bg-amber-100 text-amber-700 text-xs px-2 py-0.5 rounded-full font-medium">
                    Premium
                  </span>
                )}
              </div>
              <div className="text-sm text-stone-500 mt-1">
                <span>Age: {user.age}</span>
                {getPregnancyStageLabel() && (
                  <>
                    <span className="mx-2">•</span>
                    <span>{getPregnancyStageLabel()}</span>
                  </>
                )}
              </div>
              {user.dietaryRestrictions?.length > 0 && (
                <div className="flex flex-wrap gap-1 mt-2">
                  {user.dietaryRestrictions.map((restriction) => (
                    <span
                      key={restriction}
                      className="bg-stone-100 text-stone-600 text-xs px-2 py-0.5 rounded-full"
                    >
                      {restriction}
                    </span>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Settings Items */}
      <div className="space-y-3">
        {settingsItems.map((item) => {
          const Icon = item.icon;
          const content = (
            <div
              className={`flex items-center gap-4 p-4 bg-white rounded-xl border transition-colors ${
                item.highlight
                  ? 'border-amber-300 bg-gradient-to-r from-amber-50 to-orange-50'
                  : 'border-stone-200 hover:border-stone-300'
              }`}
            >
              <div
                className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                  item.highlight ? 'bg-amber-100' : 'bg-stone-100'
                }`}
              >
                <Icon className={item.highlight ? 'text-amber-600' : 'text-stone-600'} size={20} />
              </div>
              <div className="flex-1">
                <h3 className={`font-medium ${item.highlight ? 'text-amber-800' : 'text-stone-800'}`}>
                  {item.label}
                </h3>
                <p className={`text-sm ${item.highlight ? 'text-amber-600' : 'text-stone-500'}`}>
                  {item.description}
                </p>
              </div>
              <ChevronRight className={item.highlight ? 'text-amber-400' : 'text-stone-400'} size={20} />
            </div>
          );

          if (item.to) {
            return (
              <Link
                key={item.label}
                to={item.to}
                data-testid={`settings-${item.label.toLowerCase().replace(/\s+/g, '-')}`}
              >
                {content}
              </Link>
            );
          }

          return (
            <button
              key={item.label}
              className="w-full text-left"
              onClick={item.action}
              data-testid={`settings-${item.label.toLowerCase().replace(/\s+/g, '-')}`}
            >
              {content}
            </button>
          );
        })}

        {/* Restore Purchases Button */}
        <button
          onClick={handleRestorePurchases}
          disabled={restoring}
          className="w-full text-left"
          data-testid="settings-restore-purchases"
        >
          <div className="flex items-center gap-4 p-4 bg-white rounded-xl border border-stone-200 hover:border-stone-300 transition-colors">
            <div className="w-10 h-10 bg-stone-100 rounded-lg flex items-center justify-center">
              <RefreshCw className={`text-stone-600 ${restoring ? 'animate-spin' : ''}`} size={20} />
            </div>
            <div className="flex-1">
              <h3 className="font-medium text-stone-800">Restore Purchases</h3>
              <p className="text-sm text-stone-500">Recover previous purchases</p>
            </div>
            <ChevronRight className="text-stone-400" size={20} />
          </div>
        </button>

        {/* Delete Account / Reset Profile */}
        <button
          onClick={handleDeleteAccount}
          disabled={deleting}
          className="w-full text-left"
          data-testid="settings-delete-account"
        >
          <div className="flex items-center gap-4 p-4 bg-white rounded-xl border border-red-200 hover:border-red-300 transition-colors">
            <div className="w-10 h-10 bg-red-100 rounded-lg flex items-center justify-center">
              <Trash2 className={`text-red-600 ${deleting ? 'animate-pulse' : ''}`} size={20} />
            </div>
            <div className="flex-1">
              <h3 className="font-medium text-red-700">Delete Account</h3>
              <p className="text-sm text-red-500">Permanently remove all data from our servers</p>
            </div>
            <ChevronRight className="text-red-400" size={20} />
          </div>
        </button>
      </div>

      {/* Offline Access Section */}
      <div className="mt-6 bg-white rounded-2xl p-5 border border-stone-200">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
              <Database className="text-blue-600" size={20} />
            </div>
            <div>
              <h3 className="font-semibold text-stone-800">Offline Access</h3>
              <p className="text-xs text-stone-500">Food database saved for offline use</p>
            </div>
          </div>
          <button
            onClick={handleClearCache}
            className="flex items-center gap-1.5 px-4 py-2 bg-stone-100 hover:bg-stone-200 rounded-lg transition-colors text-stone-700 text-sm"
            data-testid="clear-cache-btn"
          >
            <Trash2 size={14} />
            Clear Saved Data
          </button>
        </div>
      </div>

      {/* App Version */}
      <div className="mt-8 text-center text-xs text-stone-400">
        <p>WhatToEat v1.0.0</p>
        <p>Pregnancy Nutrition Education</p>
      </div>
    </div>
  );
}
